#include<bits/stdc++.h>
#define rep(a,b,c) for(register int c=(a);c<=(b);++c)
#define drep(a,b,c) for(register int c=(a);c>=(b);--c)
#define int long long
using namespace std;
inline int read()
{
	int res=0;char ch=getchar();bool flag=0;
	while(ch<'0'||ch>'9')flag^=(ch=='-'),ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();
	return flag ? -res : res ;
}
const int N=1e5+10;
struct BITree
{
	int t[N],n;inline int lb(int x){return x&(-x);}inline void Init(int w){n=w;}
	inline void Add(int pos,int val){while(pos<=n)t[pos]+=val,pos+=lb(pos);}
	inline int Qry(int pos){int res=0;while(pos)res+=t[pos],pos-=lb(pos);return res;}
	inline int qry(int l,int r){return Qry(r)-Qry(l-1);}
}g;
struct Node{int idx,val;inline bool operator<(const Node &a)const{return val<a.val;}}Q[N];
struct Qery{int n,m,a,idx,ans;inline bool operator<(const Qery &x)const{return a<x.a;}}q[N];
int mu[N],pm[N],cnt,d[N];bool vs[N];
inline void Init(int mx)
{
	vs[1]=1;mu[1]=1;rep(2,mx,i)
	{
		if(!vs[i])mu[pm[++cnt]=i]=-1;
		rep(1,cnt,j){if(i*pm[j]>mx)break;vs[i*pm[j]]=1;if(i%pm[j]==0)break;mu[i*pm[j]]=-mu[i];}
	}
	rep(1,mx,i){for(int j=1;j*i<=mx;++j)Q[i*j].val+=i;Q[i].idx=i;}rep(1,mx,i)d[i]=Q[i].val;sort(Q+1,Q+mx+1);
}
inline int Solve(int n,int m)
{
	int res=0;if(n>m)swap(n,m);for(int l=1,r=0;l<=n;l=r+1)
		{r=min(n/(n/l),m/(m/l));res+=(n/l)*(m/l)*(g.qry(l,r));}return res;
}
inline void Add(int k){for(int i=1;i*k<=N-10;++i)g.Add(i*k,mu[i]*d[k]);}
signed main()
{
	Init(N-10);g.Init(N-10);
//	freopen("ga.txt","r",stdin);
	int T=read();rep(1,T,i)q[i].n=read(),q[i].m=read(),q[i].a=read(),q[i].idx=i;sort(q+1,q+T+1);
	int k=1;rep(1,T,i)
	{
		while(Q[k].val<=q[i].a&&k<=N-10){Add(Q[k++].idx);}
		q[q[i].idx].ans=Solve(q[i].n,q[i].m);
	}
	rep(1,T,i)printf("%lld\n",q[i].ans&2147483647);
}
